with seed(ord,teks_code,rit_band,difficulty,stem,stem_image_svg,explanation,source_note,choices) as (values
(1,$code$4.11D.i$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which revision fixes the agreement error?$stem$,NULL,$exp$The subject is list, which is singular, so use is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The list of supplies is on the desk.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"The list of supplies are on the desk.","is_correct":false,"misconception":"Matched the verb to the object of the preposition.","misconception_tag":"subject_verb_agreement","sort_order":2},{"label":"C","body":"The supplies of list is on the desk.","is_correct":false,"misconception":"Matched the verb to the object of the preposition.","misconception_tag":"subject_verb_agreement","sort_order":3},{"label":"D","body":"The list of supplies were on the desk.","is_correct":false,"misconception":"Matched the verb to the object of the preposition.","misconception_tag":"subject_verb_agreement","sort_order":4}]$choices$::jsonb),
(2,$code$4.11D.ii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the verb that completes the sentence: Yesterday, Liam ___ a poem.$stem$,NULL,$exp$Yesterday signals past tense, so wrote is correct.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"write","is_correct":false,"misconception":"Used present or future tense with a past-time clue.","misconception_tag":"verb_tense_confusion","sort_order":1},{"label":"B","body":"wrote","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"writes","is_correct":false,"misconception":"Used present or future tense with a past-time clue.","misconception_tag":"verb_tense_confusion","sort_order":3},{"label":"D","body":"will write","is_correct":false,"misconception":"Used present or future tense with a past-time clue.","misconception_tag":"verb_tense_confusion","sort_order":4}]$choices$::jsonb),
(3,$code$4.11D.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the verb: Tomorrow, Priya ___ her project.$stem$,NULL,$exp$Tomorrow signals future tense.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"has presented","is_correct":false,"misconception":"Ignored the future-time clue.","misconception_tag":"verb_tense_confusion","sort_order":1},{"label":"B","body":"presents yesterday","is_correct":false,"misconception":"Ignored the future-time clue.","misconception_tag":"verb_tense_confusion","sort_order":2},{"label":"C","body":"will present","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"presented","is_correct":false,"misconception":"Ignored the future-time clue.","misconception_tag":"verb_tense_confusion","sort_order":4}]$choices$::jsonb),
(4,$code$4.11D.ii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses present perfect tense?$stem$,NULL,$exp$Has finished is present perfect tense.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Ava finished the chapter.","is_correct":false,"misconception":"Confused simple tense with perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":1},{"label":"B","body":"Ava will finish the chapter.","is_correct":false,"misconception":"Confused simple tense with perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":2},{"label":"C","body":"Ava finishes the chapter.","is_correct":false,"misconception":"Confused simple tense with perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":3},{"label":"D","body":"Ava has finished the chapter.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(5,$code$4.11D.ii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision keeps the tense consistent?$stem$,NULL,$exp$Packed and walked are both past tense.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Hana packed lunch and walked to school.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"Hana packed lunch and walks to school.","is_correct":false,"misconception":"Mixed verb tenses in one sentence.","misconception_tag":"verb_tense_confusion","sort_order":2},{"label":"C","body":"Hana packs lunch and walked to school.","is_correct":false,"misconception":"Mixed verb tenses in one sentence.","misconception_tag":"verb_tense_confusion","sort_order":3},{"label":"D","body":"Hana will pack lunch and walked to school.","is_correct":false,"misconception":"Mixed verb tenses in one sentence.","misconception_tag":"verb_tense_confusion","sort_order":4}]$choices$::jsonb),
(6,$code$4.11D.ii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence correctly uses past perfect?$stem$,NULL,$exp$Had stopped shows an action completed before a past time.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"By noon, the rain stops.","is_correct":false,"misconception":"Used the wrong perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":1},{"label":"B","body":"By noon, the rain had stopped.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"By noon, the rain has stopped.","is_correct":false,"misconception":"Used the wrong perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":3},{"label":"D","body":"By noon, the rain will stop.","is_correct":false,"misconception":"Used the wrong perfect tense.","misconception_tag":"verb_tense_confusion","sort_order":4}]$choices$::jsonb),
(7,$code$4.11D.iii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence uses a possessive noun correctly?$stem$,NULL,$exp$Maya's shows the pencil belongs to Maya.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Maya pencil's rolled away.","is_correct":false,"misconception":"Put the apostrophe in the wrong place.","misconception_tag":"plural_form_confusion","sort_order":1},{"label":"B","body":"Mayas' pencil rolled away.","is_correct":false,"misconception":"Put the apostrophe in the wrong place.","misconception_tag":"plural_form_confusion","sort_order":2},{"label":"C","body":"Maya's pencil rolled away.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Mayas pencil rolled away.","is_correct":false,"misconception":"Put the apostrophe in the wrong place.","misconception_tag":"plural_form_confusion","sort_order":4}]$choices$::jsonb),
(8,$code$4.11D.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct plural: The ___ flew over the pond.$stem$,NULL,$exp$Geese is the plural of goose.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"gooses","is_correct":false,"misconception":"Used a regular plural for an irregular noun.","misconception_tag":"plural_form_confusion","sort_order":1},{"label":"B","body":"goose","is_correct":false,"misconception":"Used a regular plural for an irregular noun.","misconception_tag":"plural_form_confusion","sort_order":2},{"label":"C","body":"geeses","is_correct":false,"misconception":"Used a regular plural for an irregular noun.","misconception_tag":"plural_form_confusion","sort_order":3},{"label":"D","body":"geese","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(9,$code$4.11D.iii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which word is a proper noun?$stem$,NULL,$exp$Texas names a specific place, so it is proper.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Texas","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"river","is_correct":false,"misconception":"Confused common and proper nouns.","misconception_tag":"plural_form_confusion","sort_order":2},{"label":"C","body":"teacher","is_correct":false,"misconception":"Confused common and proper nouns.","misconception_tag":"plural_form_confusion","sort_order":3},{"label":"D","body":"museum","is_correct":false,"misconception":"Confused common and proper nouns.","misconception_tag":"plural_form_confusion","sort_order":4}]$choices$::jsonb),
(10,$code$4.11D.iii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence uses a plural possessive correctly?$stem$,NULL,$exp$Teachers' shows the lounge belongs to more than one teacher.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The teacher lounge's is quiet.","is_correct":false,"misconception":"Confused singular and plural possessive forms.","misconception_tag":"plural_form_confusion","sort_order":1},{"label":"B","body":"The teachers' lounge is quiet.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"The teacher's lounge are quiet.","is_correct":false,"misconception":"Confused singular and plural possessive forms.","misconception_tag":"plural_form_confusion","sort_order":3},{"label":"D","body":"The teachers lounge is quiet.","is_correct":false,"misconception":"Confused singular and plural possessive forms.","misconception_tag":"plural_form_confusion","sort_order":4}]$choices$::jsonb),
(11,$code$4.11D.iii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which revision fixes the noun error?$stem$,NULL,$exp$Children is already plural, so use children's.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The childrens' coats hung by the door.","is_correct":false,"misconception":"Added plural possessive rules to an irregular plural incorrectly.","misconception_tag":"plural_form_confusion","sort_order":1},{"label":"B","body":"The childrenses coats hung by the door.","is_correct":false,"misconception":"Added plural possessive rules to an irregular plural incorrectly.","misconception_tag":"plural_form_confusion","sort_order":2},{"label":"C","body":"The children's coats hung by the door.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"The childrens coats hung by the door.","is_correct":false,"misconception":"Added plural possessive rules to an irregular plural incorrectly.","misconception_tag":"plural_form_confusion","sort_order":4}]$choices$::jsonb),
(12,$code$4.11D.iv$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the correct article: Hana saw ___ owl in the tree.$stem$,NULL,$exp$Use an before a vowel sound.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"a","is_correct":false,"misconception":"Chose the wrong article for the beginning sound.","misconception_tag":"article_a_an_misuse","sort_order":1},{"label":"B","body":"thee","is_correct":false,"misconception":"Chose the wrong article for the beginning sound.","misconception_tag":"article_a_an_misuse","sort_order":2},{"label":"C","body":"some an","is_correct":false,"misconception":"Chose the wrong article for the beginning sound.","misconception_tag":"article_a_an_misuse","sort_order":3},{"label":"D","body":"an","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(13,$code$4.11D.iv$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses a comparative adjective correctly?$stem$,NULL,$exp$Use steeper to compare two things.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"This trail is steeper than that one.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"This trail is steepest than that one.","is_correct":false,"misconception":"Used a superlative or double comparison.","misconception_tag":"article_a_an_misuse","sort_order":2},{"label":"C","body":"This trail is more steeper than that one.","is_correct":false,"misconception":"Used a superlative or double comparison.","misconception_tag":"article_a_an_misuse","sort_order":3},{"label":"D","body":"This trail is most steep than that one.","is_correct":false,"misconception":"Used a superlative or double comparison.","misconception_tag":"article_a_an_misuse","sort_order":4}]$choices$::jsonb),
(14,$code$4.11D.iv$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the best adjective: The ___ answer explained every step.$stem$,NULL,$exp$Clear describes the noun answer.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"clearerly","is_correct":false,"misconception":"Chose an adverb or noun form instead of an adjective.","misconception_tag":"article_a_an_misuse","sort_order":1},{"label":"B","body":"clear","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"clearly","is_correct":false,"misconception":"Chose an adverb or noun form instead of an adjective.","misconception_tag":"article_a_an_misuse","sort_order":3},{"label":"D","body":"clearness","is_correct":false,"misconception":"Chose an adverb or noun form instead of an adjective.","misconception_tag":"article_a_an_misuse","sort_order":4}]$choices$::jsonb),
(15,$code$4.11D.iv$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence uses a superlative correctly?$stem$,NULL,$exp$Brightest compares one poster with all the others.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Of all the posters, Zoe's is more brightest.","is_correct":false,"misconception":"Used comparative form for more than two things.","misconception_tag":"article_a_an_misuse","sort_order":1},{"label":"B","body":"Of all the posters, Zoe's is bright than.","is_correct":false,"misconception":"Used comparative form for more than two things.","misconception_tag":"article_a_an_misuse","sort_order":2},{"label":"C","body":"Of all the posters, Zoe's is the brightest.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Of all the posters, Zoe's is brighter.","is_correct":false,"misconception":"Used comparative form for more than two things.","misconception_tag":"article_a_an_misuse","sort_order":4}]$choices$::jsonb),
(16,$code$4.11D.v$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which word is an adverb?$stem$,NULL,$exp$Quickly tells how an action is done.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"quick","is_correct":false,"misconception":"Confused adjective and adverb forms.","misconception_tag":"part_of_speech_confusion","sort_order":1},{"label":"B","body":"quicker","is_correct":false,"misconception":"Confused adjective and adverb forms.","misconception_tag":"part_of_speech_confusion","sort_order":2},{"label":"C","body":"quickness","is_correct":false,"misconception":"Confused adjective and adverb forms.","misconception_tag":"part_of_speech_confusion","sort_order":3},{"label":"D","body":"quickly","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(17,$code$4.11D.v$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the adverb: Imani ___ checks her work before turning it in.$stem$,NULL,$exp$Always tells how often Imani checks her work.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"always","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"bright","is_correct":false,"misconception":"Chose a word that does not tell frequency.","misconception_tag":"part_of_speech_confusion","sort_order":2},{"label":"C","body":"careful","is_correct":false,"misconception":"Chose a word that does not tell frequency.","misconception_tag":"part_of_speech_confusion","sort_order":3},{"label":"D","body":"silent","is_correct":false,"misconception":"Chose a word that does not tell frequency.","misconception_tag":"part_of_speech_confusion","sort_order":4}]$choices$::jsonb),
(18,$code$4.11D.v$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses an adverb of manner?$stem$,NULL,$exp$Softly tells how Theo spoke.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Theo liked softness.","is_correct":false,"misconception":"Confused an adjective or noun with an adverb.","misconception_tag":"part_of_speech_confusion","sort_order":1},{"label":"B","body":"Theo spoke softly to the kitten.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"Theo held the soft kitten.","is_correct":false,"misconception":"Confused an adjective or noun with an adverb.","misconception_tag":"part_of_speech_confusion","sort_order":3},{"label":"D","body":"Theo chose a softer blanket.","is_correct":false,"misconception":"Confused an adjective or noun with an adverb.","misconception_tag":"part_of_speech_confusion","sort_order":4}]$choices$::jsonb),
(19,$code$4.11D.v$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision uses the adverb correctly?$stem$,NULL,$exp$Carefully describes how he answered.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Aarav careful answered the question.","is_correct":false,"misconception":"Placed or formed the adverb incorrectly.","misconception_tag":"part_of_speech_confusion","sort_order":1},{"label":"B","body":"Aarav answered the carefully question.","is_correct":false,"misconception":"Placed or formed the adverb incorrectly.","misconception_tag":"part_of_speech_confusion","sort_order":2},{"label":"C","body":"Aarav answered the question carefully.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Aarav answered the question careful.","is_correct":false,"misconception":"Placed or formed the adverb incorrectly.","misconception_tag":"part_of_speech_confusion","sort_order":4}]$choices$::jsonb),
(20,$code$4.11D.vi$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the preposition: The book is ___ the desk.$stem$,NULL,$exp$Under shows where the book is.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"quickly","is_correct":false,"misconception":"Chose a word that is not a preposition.","misconception_tag":"preposition_use","sort_order":1},{"label":"B","body":"blue","is_correct":false,"misconception":"Chose a word that is not a preposition.","misconception_tag":"preposition_use","sort_order":2},{"label":"C","body":"because","is_correct":false,"misconception":"Chose a word that is not a preposition.","misconception_tag":"preposition_use","sort_order":3},{"label":"D","body":"under","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb)
), ins as (
  insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format)
  select 'language'::map_subject,4,s.id,null,seed.rit_band,seed.difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq'
  from seed
  join map_standards s on s.grade=4 and s.subject='language'::map_subject and s.teks_code=seed.teks_code
  where not exists (
    select 1 from map_questions q
    where q.grade=4 and q.subject='language'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.explanation=seed.explanation
  )
  returning id, stem, explanation, source_note
)
insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order)
select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order
from ins
join seed on seed.stem=ins.stem and seed.explanation=ins.explanation and seed.source_note=ins.source_note
cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1), body text, is_correct boolean, misconception text, misconception_tag text, sort_order smallint);